#include<bits/stdc++.h>
using namespace std;

const int N = 205;

int n, m, s;

int g[N][N];

int dis[N], pre[N];
bool vis[N];

void Dijkstra(bool flag) {
	memset(dis, 0x3f, sizeof dis);
	memset(vis, 0, sizeof vis);
	dis[s] = 0;
	for (int i = 1; i <= n; i++) {
    	int u = 0, mind = 0x3f3f3f3f;
    	for (int j = 1; j <= n; j++)
    		if (!vis[j] && dis[j] < mind) u = j, mind = dis[j];
    	vis[u] = true;
    	for(int v = 1; v <= n; v++) {
    		if(g[u][v]) {
    			int w = g[u][v];
    			if (dis[v] > dis[u] + w) { 
    				dis[v] = dis[u] + w;
    				if(flag) pre[v] = u;
    			}
    		}
    	}
	}
}

int main()
{
    cin.tie(0) -> sync_with_stdio(0);
    cin >> n >> m;
    s = 1;
    memset(g, 0x3f, sizeof g);
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        g[u][v] = g[v][u] = w;
    }
    Dijkstra(1);
    int x = n, ans = 0, d = dis[n];
    while(x != 1)
    {
    	g[x][pre[x]] *= 2;
    	g[pre[x]][x] *= 2;
    	Dijkstra(0);
    	ans = max(ans, dis[n] - d);
    	g[x][pre[x]] /= 2;
    	g[pre[x]][x] /= 2;
    	x = pre[x];
    }
    cout << ans;
    return 0;
}
